export * from './timeline-connector.component';
export * from './timeline-content.component';
export * from './timeline-item.component';
export * from './timeline-marker.component';
export * from './timeline-opposite.component';
export * from './timeline.component';
export * from './timeline.variants';
export * from './timeline.imports';

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbTimelineComponent } from './timeline.component';

@Component({
  selector: 'hb-timeline-connector',
  template: ``,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'timeline-connector-custom'",
  },
  exportAs: 'hbTimelineConnector',
})
export class HbTimelineConnectorComponent {
  private readonly timeline = inject(HbTimelineComponent);
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn(
      'block bg-border',
      this.timeline.layout() === 'vertical' ? 'w-0.5 flex-1' : 'h-0.5 flex-1',
      this.class(),
    ),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';

@Component({
  selector: 'hb-timeline-content',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'timeline-content'",
  },
  exportAs: 'hbTimelineContent',
})
export class HbTimelineContentComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() => cn('block text-sm', this.class()));
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  inject,
  input,
  output,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbTimelineConnectorComponent } from './timeline-connector.component';
import { HbTimelineMarkerComponent } from './timeline-marker.component';
import { HbTimelineOppositeComponent } from './timeline-opposite.component';
import { HbTimelineComponent } from './timeline.component';

@Component({
  selector: 'hb-timeline-item',
  template: `
    @if (hasOpposite()) {
      <div data-slot="timeline-opposite-zone" [class]="oppositeZoneClasses()">
        <ng-content select="hb-timeline-opposite" />
      </div>
    }
    <div [class]="separatorClasses()">
      <div class="relative z-10 flex shrink-0 items-center justify-center">
        <ng-content select="hb-timeline-marker" />
        @if (!hasMarker()) {
          <span class="size-3 shrink-0 rounded-full bg-muted-foreground/40"></span>
        }
      </div>
      <div data-slot="timeline-connector" [class]="connectorZoneClasses()">
        <ng-content select="hb-timeline-connector" />
        @if (!hasConnector()) {
          <span [class]="defaultLineClasses()"></span>
        }
      </div>
    </div>
    <div data-slot="timeline-content-zone" [class]="contentZoneClasses()">
      <ng-content select="hb-timeline-content" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'itemClasses()',
    '[attr.data-slot]': "'timeline-item'",
    '[attr.data-interactive]': 'hbInteractive() || null',
    '[attr.role]': "hbInteractive() ? 'button' : 'listitem'",
    '[attr.tabindex]': 'hbInteractive() ? 0 : null',
    '(click)': 'onActivate()',
    '(keydown)': 'onKeydown($event)',
  },
  exportAs: 'hbTimelineItem',
})
export class HbTimelineItemComponent {
  private readonly timeline = inject(HbTimelineComponent);

  readonly hbInteractive = input(false, { transform: booleanAttribute });
  readonly class = input<ClassValue>('');
  readonly hbSelect = output<void>();

  private readonly markerQuery = contentChild(HbTimelineMarkerComponent);
  private readonly oppositeQuery = contentChild(HbTimelineOppositeComponent);
  private readonly connectorQuery = contentChild(HbTimelineConnectorComponent);
  protected readonly hasMarker = computed(() => !!this.markerQuery());
  protected readonly hasOpposite = computed(() => !!this.oppositeQuery());
  protected readonly hasConnector = computed(() => !!this.connectorQuery());

  private readonly vertical = computed(() => this.timeline.layout() === 'vertical');

  protected readonly itemClasses = computed(() => {
    const v = this.vertical();
    const align = this.timeline.align();
    return cn(
      'group/timeline-item relative flex',
      v ? 'flex-row' : 'shrink-0 flex-col',
      v && align === 'left' && 'flex-row-reverse',
      !v && align === 'top' && 'flex-col-reverse',
      align === 'alternate' &&
        (v ? '[&:nth-child(even)]:flex-row-reverse' : '[&:nth-child(even)]:flex-col-reverse'),
      v &&
        align === 'alternate' &&
        '[&>[data-slot=timeline-opposite-zone]]:text-right [&>[data-slot=timeline-content-zone]]:text-left [&:nth-child(even)>[data-slot=timeline-opposite-zone]]:text-left [&:nth-child(even)>[data-slot=timeline-content-zone]]:text-right',
      this.hbInteractive() &&
        'cursor-pointer rounded-md outline-none transition-colors hover:bg-accent/40 focus-visible:ring-[3px] focus-visible:ring-ring/50',
      this.class(),
    );
  });

  protected readonly separatorClasses = computed(() =>
    cn(
      'flex shrink-0 self-stretch',
      this.vertical() ? 'flex-col items-center px-2' : 'flex-row items-center py-3',
    ),
  );
  protected readonly connectorZoneClasses = computed(() =>
    cn(
      'flex flex-1 items-center justify-center',
      this.vertical() ? 'flex-col' : 'flex-row',
    ),
  );
  protected readonly defaultLineClasses = computed(() =>
    cn('bg-border', this.vertical() ? 'w-0.5 flex-1' : 'h-0.5 flex-1'),
  );
  protected readonly oppositeZoneClasses = computed(() => {
    const align = this.timeline.align();
    if (!this.vertical()) return 'flex-1 px-3 pb-3 text-center';
    const base = 'flex-1 basis-0 px-3 py-1.5';
    if (align === 'right') return cn(base, 'text-right');
    if (align === 'left') return cn(base, 'text-left');
    return base;
  });
  protected readonly contentZoneClasses = computed(() => {
    const align = this.timeline.align();
    if (!this.vertical()) return 'min-w-0 flex-1 px-3 pt-3 text-center';
    const base = 'min-w-0 flex-1 basis-0 px-3 pb-8';
    if (align === 'right') return cn(base, 'text-left');
    if (align === 'left') return cn(base, 'text-right');
    return base;
  });

  protected onActivate(): void {
    if (this.hbInteractive()) this.hbSelect.emit();
  }
  protected onKeydown(event: KeyboardEvent): void {
    if (this.hbInteractive() && (event.key === 'Enter' || event.key === ' ')) {
      event.preventDefault();
      this.hbSelect.emit();
    }
  }
}

import {
  afterNextRender,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  inject,
  input,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon } from '@ng-icons/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  timelineMarkerVariants,
  type HbTimelineColor,
  type HbTimelineMarkerVariant,
} from './timeline.variants';

@Component({
  selector: 'hb-timeline-marker',
  imports: [NgIcon],
  template: `
    @if (hbIcon()) {
      <ng-icon [name]="hbIcon()" />
    } @else {
      <ng-content />
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'timeline-marker'",
  },
  exportAs: 'hbTimelineMarker',
})
export class HbTimelineMarkerComponent {
  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);

  readonly hbIcon = input<string>('');
  readonly hbColor = input<HbTimelineColor>('primary');
  readonly hbVariant = input<HbTimelineMarkerVariant>('solid');
  readonly class = input<ClassValue>('');

  private readonly hasContent = signal(false);

  protected readonly classes = computed(() => {
    const swatch = timelineMarkerVariants({ color: this.hbColor(), variant: this.hbVariant() });
    if (this.hbIcon()) return cn('size-7 text-sm', swatch, this.class());
    if (this.hasContent()) return cn('inline-flex shrink-0 items-center justify-center', this.class());
    return cn('size-3', swatch, this.class());
  });

  constructor() {
    afterNextRender(() => {
      const el = this.host.nativeElement;
      this.hasContent.set(el.childElementCount > 0 || (el.textContent ?? '').trim().length > 0);
    });
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';

@Component({
  selector: 'hb-timeline-opposite',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'timeline-opposite'",
  },
  exportAs: 'hbTimelineOpposite',
})
export class HbTimelineOppositeComponent {
  readonly class = input<ClassValue>('');
  protected readonly classes = computed(() => cn('block text-sm text-muted-foreground', this.class()));
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { type HbTimelineAlign, type HbTimelineLayout } from './timeline.variants';

@Component({
  selector: 'hb-timeline',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'list',
    '[class]': 'classes()',
    '[attr.data-slot]': "'timeline'",
    '[attr.data-layout]': 'hbLayout()',
    '[attr.data-align]': 'hbAlign()',
  },
  exportAs: 'hbTimeline',
})
export class HbTimelineComponent {
  readonly hbLayout = input<HbTimelineLayout>('vertical');
  readonly hbAlign = input<HbTimelineAlign>('left');
  readonly class = input<ClassValue>('');

  readonly layout = this.hbLayout;
  readonly align = this.hbAlign;

  protected readonly classes = computed(() =>
    cn(
      'group/timeline flex',
      this.hbLayout() === 'vertical' ? 'flex-col' : 'flex-row overflow-x-auto',
      '[&>[data-slot=timeline-item]:last-child_[data-slot=timeline-connector]]:hidden',
      this.class(),
    ),
  );
}

import { HbTimelineConnectorComponent } from './timeline-connector.component';
import { HbTimelineContentComponent } from './timeline-content.component';
import { HbTimelineItemComponent } from './timeline-item.component';
import { HbTimelineMarkerComponent } from './timeline-marker.component';
import { HbTimelineOppositeComponent } from './timeline-opposite.component';
import { HbTimelineComponent } from './timeline.component';

export const HbTimelineImports = [
  HbTimelineComponent,
  HbTimelineItemComponent,
  HbTimelineMarkerComponent,
  HbTimelineContentComponent,
  HbTimelineOppositeComponent,
  HbTimelineConnectorComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

export type HbTimelineLayout = 'vertical' | 'horizontal';
export type HbTimelineAlign = 'left' | 'right' | 'top' | 'bottom' | 'alternate';

export const timelineMarkerVariants = cva(
  'flex shrink-0 items-center justify-center rounded-full [&_ng-icon]:text-current',
  {
    variants: {
      color: {
        default: '',
        primary: '',
        success: '',
        warning: '',
        destructive: '',
        muted: '',
      },
      variant: {
        solid: '',
        soft: '',
        outline: 'border-2 bg-background',
      },
    },
    compoundVariants: [
      { variant: 'solid', color: 'default', class: 'bg-foreground text-background' },
      { variant: 'solid', color: 'primary', class: 'bg-primary text-primary-foreground' },
      { variant: 'solid', color: 'success', class: 'bg-success text-success-foreground' },
      { variant: 'solid', color: 'warning', class: 'bg-warning text-warning-foreground' },
      { variant: 'solid', color: 'destructive', class: 'bg-destructive text-destructive-foreground' },
      { variant: 'solid', color: 'muted', class: 'bg-muted text-muted-foreground' },
      { variant: 'soft', color: 'default', class: 'bg-muted text-foreground' },
      { variant: 'soft', color: 'primary', class: 'bg-primary/15 text-primary' },
      { variant: 'soft', color: 'success', class: 'bg-success/15 text-success' },
      { variant: 'soft', color: 'warning', class: 'bg-warning/15 text-warning' },
      { variant: 'soft', color: 'destructive', class: 'bg-destructive/15 text-destructive' },
      { variant: 'soft', color: 'muted', class: 'bg-muted text-muted-foreground' },
      { variant: 'outline', color: 'default', class: 'border-foreground text-foreground' },
      { variant: 'outline', color: 'primary', class: 'border-primary text-primary' },
      { variant: 'outline', color: 'success', class: 'border-success text-success' },
      { variant: 'outline', color: 'warning', class: 'border-warning text-warning' },
      { variant: 'outline', color: 'destructive', class: 'border-destructive text-destructive' },
      { variant: 'outline', color: 'muted', class: 'border-muted-foreground text-muted-foreground' },
    ],
    defaultVariants: { color: 'primary', variant: 'solid' },
  },
);

export type HbTimelineColor = NonNullable<VariantProps<typeof timelineMarkerVariants>['color']>;
export type HbTimelineMarkerVariant = NonNullable<VariantProps<typeof timelineMarkerVariants>['variant']>;

